import React, { useState, useEffect, useCallback } from 'react';
import io from 'socket.io-client';

// Socket.io connection
const SOCKET_URL = process.env.REACT_APP_API_URL || 'http://localhost:3000';
const socket = io(SOCKET_URL);

// Voice recognition setup
const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
let recognition = null;
if (SpeechRecognition) {
  recognition = new SpeechRecognition();
  recognition.continuous = false;
  recognition.lang = 'vi-VN';
  recognition.interimResults = false;
}

function App() {
  // State
  const [systemStatus, setSystemStatus] = useState([]);
  const [logs, setLogs] = useState([]);
  const [mqttStatus, setMqttStatus] = useState({ connected: false });
  const [loading, setLoading] = useState(true);
  const [dispensing, setDispensing] = useState(false);
  const [listening, setListening] = useState(false);
  const [voiceTranscript, setVoiceTranscript] = useState('');

  // Connect to socket and get initial data
  useEffect(() => {
    socket.emit('request:initial-data');

    socket.on('connect', () => {
      console.log('Socket connected');
    });

    socket.on('medicine:logs', (data) => {
      setLogs(data);
      setLoading(false);
    });

    socket.on('system:status', (data) => {
      setSystemStatus(data);
    });

    socket.on('medicine:status', (data) => {
      console.log('Medicine status:', data);
      // Refresh logs after status update
      socket.emit('request:initial-data');
    });

    socket.on('mqtt:status', (data) => {
      setMqttStatus(data);
    });

    return () => {
      socket.off('connect');
      socket.off('medicine:logs');
      socket.off('system:status');
      socket.off('medicine:status');
      socket.off('mqtt:status');
    };
  }, []);

  // Dispense medicine
  const dispense = useCallback(async (slot) => {
    setDispensing(true);
    try {
      const response = await fetch(`${SOCKET_URL}/api/medicine/dispense`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ slot })
      });
      const data = await response.json();
      console.log('Dispense response:', data);
    } catch (error) {
      console.error('Dispense error:', error);
    } finally {
      setDispensing(false);
    }
  }, []);

  // Voice recognition handlers
  const startListening = useCallback(() => {
    if (!recognition) {
      alert('Trình duyệt không hỗ trợ nhận dạng giọng nói');
      return;
    }

    setListening(true);
    setVoiceTranscript('Đang nghe...');

    recognition.start();
  }, []);

  const handleVoiceResult = useCallback(async (event) => {
    const transcript = event.results[0][0].transcript;
    setVoiceTranscript(transcript);
    console.log('Voice transcript:', transcript);

    // Parse command
    const text = transcript.toLowerCase();

    // Save voice command to database
    try {
      await fetch(`${SOCKET_URL}/api/medicine/voice`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          command: transcript,
          slot: null,
          confidence: event.results[0][0].confidence
        })
      });
    } catch (error) {
      console.error('Save voice error:', error);
    }

    // Determine slot from voice
    const slot1Patterns = ['thuốc 1', 'thuốc số 1', 'uống thuốc 1', 'cho tôi thuốc 1', 'cấp 1', '1'];
    const slot2Patterns = ['thuốc 2', 'thuốc số 2', 'uống thuốc 2', 'cho tôi thuốc 2', 'cấp 2', '2'];
    const morningPatterns = ['sáng', 'buổi sáng'];
    const anyPatterns = ['thuốc', 'u��ng thuốc', 'phát thuốc', 'lấy thuốc'];

    let slot = null;

    // Check for specific slot
    if (slot1Patterns.some(p => text.includes(p))) {
      slot = 1;
    } else if (slot2Patterns.some(p => text.includes(p))) {
      slot = 2;
    }
    // Check for general medicine command
    else if (anyPatterns.some(p => text.includes(p))) {
      if (slot1Patterns.some(p => text.includes(p))) {
        slot = 1;
      } else if (slot2Patterns.some(p => text.includes(p))) {
        slot = 2;
      } else {
        // Default to slot 1 for general commands
        slot = 1;
      }
    }

    if (slot) {
      dispense(slot);
      setVoiceTranscript(`Đã phát thuốc số ${slot}`);
    } else {
      setVoiceTranscript(`Không hiểu lệnh: ${transcript}`);
    }

    setTimeout(() => setListening(false), 2000);
  }, [dispense]);

  const handleVoiceError = useCallback((event) => {
    console.error('Voice recognition error:', event.error);
    setVoiceTranscript('Lỗi nhận dạng giọng nói');
    setListening(false);
  }, []);

  const handleVoiceEnd = useCallback(() => {
    setListening(false);
  }, []);

  // Setup voice recognition
  useEffect(() => {
    if (recognition) {
      recognition.onresult = handleVoiceResult;
      recognition.onerror = handleVoiceError;
      recognition.onend = handleVoiceEnd;
    }
  }, [handleVoiceResult, handleVoiceError, handleVoiceEnd]);

  // Get status helper
  const getStatus = (component) => {
    const item = systemStatus.find(s => s.component === component);
    return item ? item.status : 'unknown';
  };

  // Format time
  const formatTime = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleString('vi-VN');
  };

  // Get status text
  const getStatusText = (status) => {
    switch (status) {
      case 'online': return 'Hoạt động';
      case 'offline': return 'Offline';
      default: return status;
    }
  };

  return (
    <div id="app">
      <header className="header">
        <h1>Hộp Thuốc Thông Minh</h1>
        <p>Điều khiển bằng giọng nói - Realtime Dashboard</p>
      </header>

      <div className="container">
        {/* Status Cards */}
        <div className="dashboard">
          <div className="card">
            <h2>Trạng Thái Hệ Thống</h2>
            <div className="status-grid">
              <div className="status-item">
                <span className={`status-dot ${mqttStatus.connected ? 'online' : 'offline'}`}></span>
                <span className="status-label">MQTT Broker</span>
              </div>
              <div className="status-item">
                <span className={`status-dot ${getStatus('esp32') === 'online' ? 'online' : 'offline'}`}></span>
                <span className="status-label">ESP32</span>
              </div>
              <div className="status-item">
                <span className={`status-dot ${getStatus('servo1') === 'online' ? 'online' : 'warning'}`}></span>
                <span className="status-label">Servo 1</span>
              </div>
              <div className="status-item">
                <span className={`status-dot ${getStatus('servo2') === 'online' ? 'online' : 'warning'}`}></span>
                <span className="status-label">Servo 2</span>
              </div>
              <div className="status-item">
                <span className={`status-dot ${getStatus('ir_sensor') === 'online' ? 'online' : 'warning'}`}></span>
                <span className="status-label">Cảm biến IR</span>
              </div>
            </div>
          </div>

          <div className="card">
            <h2>Điều Khiển</h2>
            <div className="control-buttons">
              <button
                className="btn btn-primary"
                onClick={() => dispense(1)}
                disabled={dispensing}
              >
                Phát Thuốc 1
              </button>
              <button
                className="btn btn-secondary"
                onClick={() => dispense(2)}
                disabled={dispensing}
              >
                Phát Thuốc 2
              </button>
            </div>
            {listening && (
              <div className="voice-status">
                {voiceTranscript}
              </div>
            )}
            {recognition && (
              <button
                className={`btn voice-btn ${listening ? 'listening' : ''}`}
                onClick={startListening}
                disabled={listening}
              >
                {listening ? 'Đang nghe...' : '🎤 Điều khiển bằng giọng nói'}
              </button>
            )}
          </div>
        </div>

        {/* Logs */}
        <div className="card">
          <h2>Lịch Sử Phát Thuốc</h2>
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : logs.length === 0 ? (
            <div className="empty-state">
              Chưa có lịch sử phát thuốc
            </div>
          ) : (
            <div className="btn-list">
              {logs.map((log, index) => (
                <div key={index} className={`log-item ${log.status}`}>
                  <div>
                    <span className="log-slot">Thuốc {log.slot}</span>
                    <span className="log-time">{formatTime(log.created_at)}</span>
                  </div>
                  <span className={`log-status ${log.status}`}>
                    {log.status === 'success' ? 'Thành công' :
                     log.status === 'fail' ? 'Thất bại' : 'Không phát hiện'}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
